+    fn diagnostics_policy_error_makes_unhealthy() {
+        let diag = make_diagnostics(
+            HostHealthStatus::Healthy,
+            MeshStatus::Connected,
+            PolicyEngineStatus::Error,
+            0,
+        );
+        assert_eq!(diag.aggregate_status(), HostHealthStatus::Unhealthy);
+    }
+
+    #[test]
